"""GDAL-based GeoTIFF implementation."""

from __future__ import annotations

from typing import TYPE_CHECKING

import numpy as np
from osgeo import gdal

from geosat.cloud.cppraster import RasterFunctionType
from geosat.cloud.rasterization import GeoTransform, Rasterizer
from geosat.tools.urlprotocol import UrlProtocols, UrlWriter

if TYPE_CHECKING:
    from typing import Optional, Tuple

gdal.UseExceptions()

_np_dtype_to_gdal_type = {
    # Unsigned versions
    np.dtype("uint8"): gdal.GDT_Byte,
    np.dtype("uint16"): gdal.GDT_UInt16,
    np.dtype("uint32"): gdal.GDT_UInt32,
    # uint64 not supported
    # Signed versions
    np.dtype("int8"): gdal.GDT_Byte,
    np.dtype("int16"): gdal.GDT_Int16,
    np.dtype("int32"): gdal.GDT_Int32,
    # Floating point versions
    np.dtype("f4"): gdal.GDT_Float32,
    np.dtype("f8"): gdal.GDT_Float64,
}


def create_rasterizer_from_gdal_dataset(
    dataset: gdal.Dataset,
    raster_fn: RasterFunctionType = RasterFunctionType.PixelIsGlobal,
    precision_ndigits: Optional[int] = None,
    include_img_array: bool = False,
) -> Tuple[Rasterizer, Optional[np.ndarray]]:
    """Returns a tuple (rasterizer, img) with img being a numpy array with the content of the raster."""
    (
        gt_xmin,
        gt_xprecision,
        gt_xskew,
        gt_ymax,
        gt_yskew,
        gt_yprecision,
    ) = dataset.GetGeoTransform()
    xprecision = (
        gt_xprecision
        if precision_ndigits is None
        else round(gt_xprecision, precision_ndigits)
    )
    yprecision = (
        gt_yprecision
        if precision_ndigits is None
        else round(gt_yprecision, precision_ndigits)
    )
    dataset_geotransform = GeoTransform(
        gt_xmin, xprecision, gt_xskew, gt_ymax, gt_yskew, yprecision
    )
    rasterizer = Rasterizer(
        dataset_geotransform,
        (dataset.RasterYSize, dataset.RasterXSize),
        raster_fn,
    )  # As it is gdal, (xmin, ymax) are the top left corner of top left pixel

    if not include_img_array:
        return rasterizer, None

    pixels_arrays = [
        np.expand_dims(dataset.GetRasterBand(i).ReadAsArray(), axis=2)
        for i in range(1, dataset.RasterCount + 1)
    ]
    pixels_array = np.concatenate(pixels_arrays, axis=2)
    return rasterizer, pixels_array


def write_rasterizer_image_as_geotiff(
    rasterizer: Rasterizer,
    image: np.ndarray,
    path: str,
    spatial_reference_wkt: Optional[str] = None,
    no_data: int = 0,
) -> None:
    """Helper function to save a raster with this specific rasterizer geotransform.

    Consider using ``cloud.metadata.get("srs_wkt", None)`` to deduce the spatial
    reference WKT directly from a cloud when rasterizing a ``PointCloud``.
    """
    write_image_as_geotiff(
        image, path, rasterizer.geo_transform, spatial_reference_wkt, no_data
    )


def get_geotiff_data(
    image: np.ndarray,
    geo_transform: GeoTransform,
    spatial_reference_wkt: Optional[str],
    no_data: int,
) -> bytes:
    try:
        num_channels = image.shape[2]
    except IndexError:
        num_channels = 1
        image = image[..., np.newaxis]

    dst: gdal.Dataset = gdal.GetDriverByName("MEM").Create(
        "",
        image.shape[1],
        image.shape[0],
        num_channels,
        _np_dtype_to_gdal_type[image.dtype],
    )
    dst.SetGeoTransform(geo_transform)
    if spatial_reference_wkt is not None:
        dst.SetProjection(spatial_reference_wkt)
    for i in range(num_channels):
        band = dst.GetRasterBand(i + 1)
        band.WriteArray(image[..., i])
        band.SetNoDataValue(no_data)
    dst.FlushCache()

    # Inspired by:
    # https://lists.osgeo.org/pipermail/gdal-dev/2016-August/045030.html
    gdal.GetDriverByName("GTiff").CreateCopy(
        "/vsimem/output.tiff", dst, options=["COMPRESS=LZW"]
    )
    # Read /vsimem/output.png
    f: gdal.VSILFILE = gdal.VSIFOpenL("/vsimem/output.tiff", "rb")
    if f is None:
        msg = "GDAL failed to open memory file '/vsimem/output.tiff'"
        raise OSError(msg)
    gdal.VSIFSeekL(f, 0, 2)  # seek to end
    size: int = gdal.VSIFTellL(f)
    gdal.VSIFSeekL(f, 0, 0)  # seek to beginning
    data: bytes = gdal.VSIFReadL(1, size, f)
    gdal.VSIFCloseL(f)

    # Cleanup
    gdal.Unlink("/vsimem/output.tiff")
    return data


def write_image_as_geotiff(
    image: np.ndarray,
    path: str,
    geo_transform: GeoTransform,
    spatial_reference_wkt: Optional[str] = None,
    no_data: int = 0,
) -> None:
    """Writes a GeoTIFF to an image file.

    To save as another format with the corresponding world position file consider
    using GeoTransform.write() and PIL: consider using:
    ``Image.fromarray(image, mode=mode).save(path, format=format, **params)``

    :param image: numpy array containing Raster data
    :param path: string with path to save raster
    :param geo_transform: Geotransform information
    :param spatial_reference_wkt: Coordinate system used, consider
        using CRS from pyproj for easier conversion
    :param no_data: No data value to be used for all bands (see
        https://gdal.org/drivers/raster/gtiff.html#nodata-value)
    """
    with UrlWriter(path, UrlProtocols()) as out:
        out.write(
            get_geotiff_data(image, geo_transform, spatial_reference_wkt, no_data)
        )
